-- WebChef — seed the recipe library.
--
-- Generated by scripts/fetch-recipes.mjs from the Spoonacular API. Do not edit
-- by hand: re-run the script to regenerate. Migrations run as a privileged role
-- and bypass RLS, which is exactly how course content is meant to be seeded.
--
-- Upserts on spoonacular_id, so applying this twice updates rows in place.

insert into recipes (
  spoonacular_id, title, description, image_url, source_url,
  ready_in_minutes, servings, ingredients, instructions
) values
  (945221, 'Watching What I Eat: Peanut Butter Banana Oat Breakfast Cookies with Carob / Chocolate Chips', 'If you want to add more gluten free and dairy free recipes to your repertoire, Watching What I Eat: Peanut Butter Bananan Oat Breakfast Cookies with Carob / Chocolate Chips might be a recipe you should try.  This recipe makes 16 servings with 103 calories, 4g of protein, and 5g of fat each.', 'https://img.spoonacular.com/recipes/945221-312x231.jpg', 'http://watching-what-i-eat.blogspot.com/2012/06/peanut-butter-banana-oat-breakfast.html', 45, 16, '[{"name":"bananas","amount":2,"unit":"","original":"2 ripe bananas, mashed until smooth & creamy"},{"name":"butter flavor shortening","amount":1,"unit":"tsp","original":"1 tsp butter flavor extract ** (optional)"},{"name":"chocolate chips","amount":0.25,"unit":"cups","original":"1/4 cup carob or chocolate chips (**optional)"},{"name":"creamy peanut butter","amount":0.33333334,"unit":"cups","original":"1/3 cup peanut butter - creamy or chunky"},{"name":"nuts","amount":0.25,"unit":"cups","original":"1/4 cup chopped nuts (peanut, walnut, or your favorite)"},{"name":"oatmeal","amount":1.5,"unit":"cups","original":"1 1/2 cups quick oatmeal - uncooked (or use old fashioned oats for more oatmeal texture)"},{"name":"unsweetened applesauce","amount":0.6666667,"unit":"cups","original":"2/3 cup unsweetened applesauce"},{"name":"vanilla extract","amount":1,"unit":"tsp","original":"1 tsp vanilla extract"},{"name":"vanilla protein powder","amount":1,"unit":"scoop","original":"1 scoop vanilla protein powder ** (can be made without, cookie will just be lower in protein)"}]'::jsonb, '["Preheat heat oven to 350 degrees.In a large bowl, mix mashed banana & peanut butter until completely combined then add in the applesauce, vanilla protein powder & the extract(s) ~ mix again until all are completely combined.","Add in the oatmeal & nuts to the banana mixture & combine. (** add the optional carob / chocolate chips at this time if you want them mixed throughout)","Let dough rest for 10 minutes.Drop cookie dough, by spoonfuls, onto a parchment paper lined cookie sheet & flatten cookies into circles. (** if you just want the carob / chocolate chips on the top of the cookies, add now)","Bake cookies approx. 20-30 minutes (some like their cookies less cooked, some cooked more - try it both ways to find which works best for your tastes) or until golden brown & done.","Remove from oven & let rest on cookie sheet for 5 minutes, then move to cooling rack. (if you want the traditional fork tong marks on the cookies, use a pizza cutter or sharp knife to score the tops of the cookies while they''re still warm)When cookies are completely cool, store in a covered container. Enjoy!...or with a cuppa tea."]'::jsonb),
  (715449, 'How to Make OREO Turkeys for Thanksgiving', 'How to Make OREO Turkeys for Thanksgiving requires about 40 minutes from start to finish.  This recipe serves 48.', 'https://img.spoonacular.com/recipes/715449-312x231.jpg', 'https://www.pinkwhen.com/oreo-cookie-balls-thanksgiving-turkey/', 40, 48, '[{"name":"oreo cookies 3 cups","amount":36,"unit":"","original":"36 OREO cookies finely crushed about 3 cups"},{"name":"cream cheese","amount":1,"unit":"pkg","original":"1 package 8oz. cream cheese (softened)"},{"name":"semi baking chocolate","amount":16,"unit":"oz","original":"4 4oz. semi sweet baking chocolate (melted)"},{"name":"candy corn","amount":48,"unit":"servings","original":"***Candy Corn"},{"name":"candy eyes","amount":48,"unit":"servings","original":"***Candy eyes"},{"name":"icing","amount":48,"unit":"servings","original":"***Icing"}]'::jsonb, '["Take a package of OREO cookies and crush them up finely.","Take softened cream cheese and mix well with cookie crumbs.","Roll into one inch cookie balls, and then freeze for 10 minutes.","Dip cookie balls into melted chocolate and place on a prepared cookie sheet covered with wax paper.","Place into the refrigerator for 15 minutes to an hour before decorating.","Add 5 candy corn to the back of the ball as tail feathers.","Use icing as glue to attach the candy eyes.","Cut one candy corn into pieces, using the white tip as the nose, and the orange part (cut in half) as feet."]'::jsonb),
  (776505, 'Sausage & Pepperoni Stromboli', 'Sausage & Pepperoni Stromboli takes about 28 minutes from beginning to end.  This recipe serves 6.', 'https://img.spoonacular.com/recipes/776505-312x231.jpg', 'http://asouthern-soul.blogspot.com/2014/11/sausage-pepperoni-stromboli.html', 28, 6, '[{"name":"egg","amount":1,"unit":"","original":"1 egg"},{"name":"sausage","amount":1,"unit":"lb","original":"1 lb Italian sausage"},{"name":"parmesan cheese","amount":1,"unit":"cup","original":"1 cup shredded Parmesan cheese"},{"name":"pepperoni","amount":1,"unit":"pkg","original":"1 package sliced pepperoni"},{"name":"roll of pizza dough","amount":1,"unit":"ball","original":"1 ball or roll of pizza dough (homemade is great but I used store-bought)"},{"name":"pizza sauce","amount":2,"unit":"cups","original":"2 cups pizza sauce"},{"name":"mozzarella cheese","amount":1,"unit":"cup","original":"1 cup shredded mozzarella cheese"}]'::jsonb, '["Cook Italian sausage in a medium skillet until browned.","Drain on paper towels and crumble into small pieces.","Heat oven to 450 degrees.","Place parchment paper on a baking pan and lightly flour.","Roll dough out to form a large rectangle.","Brush a thin layer of pizza sauce on dough.","Layer on crumbled sausage then mozzarella cheese.","Place pepperoni slices on top of cheese then sprinkle with 3/4 cup Parmesan cheese.Gently roll in short sides of dough to form a seal around filling.Starting on long side of dough, carefully roll into one third of Stromboli. Using parchment, roll dough again until reaching opposite end. Pinch together and place seam side down.","Mix egg with 1 tablespoon of water.","Brush egg mixture over Stromboli and sprinkle with remaining 1/4 Parmesan cheese.","Place in oven and IMMEDIATELY TURN OVEN DOWN to 350 degrees.","Bake for approximately 18 minutes.","Remove from oven and let rest for 10 minutes. Test center of turnover. If dough is not completely cooked, slice Stromboli in half and bake for additional 5-8 minutes.","Serve with warm pizza sauce"]'::jsonb),
  (715467, 'Turkey Pot Pie', 'You can never have too many main course recipes, so give Turkey Pot Pie a try.  This recipe serves 8 and costs $2.', 'https://img.spoonacular.com/recipes/715467-312x231.jpg', 'https://www.pinkwhen.com/turkey-pot-pie-recipe/', 45, 8, '[{"name":"pepper","amount":1,"unit":"tsp","original":"1 tsp black pepper"},{"name":"butter","amount":0.6666667,"unit":"cups","original":"2/3 cup butter"},{"name":"celery","amount":1,"unit":"cup","original":"1 cup chopped celery"},{"name":"celery seed","amount":0.5,"unit":"tsps","original":"1/2 tsp celery seed"},{"name":"chicken broth","amount":1.75,"unit":"cups","original":"1 3/4 cups chicken broth"},{"name":"flour","amount":0.6666667,"unit":"cups","original":"2/3 cups all-purpose flour"},{"name":"garlic powder","amount":0.5,"unit":"tsps","original":"1/2 tsp garlic powder"},{"name":"green beans","amount":20,"unit":"oz","original":"2 (10oz) cans green beans"},{"name":"seasoning","amount":0.5,"unit":"tsps","original":"1/2 tsp Italian seasoning"},{"name":"milk","amount":1.3333334,"unit":"cups","original":"1 1/3 cups milk"},{"name":"onion","amount":0.5,"unit":"cups","original":"1/2 cup chopped onion"},{"name":"onion powder","amount":0.5,"unit":"tsps","original":"1/2 tsp onion powder"},{"name":"peas and carrots","amount":20,"unit":"oz","original":"2 (10oz) cans of mixed peas and carrots"},{"name":"\" pie crusts","amount":4,"unit":"","original":"4 9″ pie crusts (not frozen)"},{"name":"salt","amount":1,"unit":"tsp","original":"1 tsp salt"},{"name":"turkey","amount":4,"unit":"cups","original":"4 cups cooked Turkey"},{"name":"pepper","amount":0.5,"unit":"tsps","original":"1/2 tsp white pepper"}]'::jsonb, '["Preheat oven to 425 degrees. Melt the butter and add the celeryand onion to a medium pot and saute over medium heat for about 8 minutes.Step 2: Stir in 2/3 cup flour, salt and pepper, celery seed, onion powder, garlic powder, and Italian seasoning. Slowly whisk in the chicken broth and milk, stirring constantly until the the mixture begins to thicken and then simmer lightly until thickened.","Remove from heat and mix with the drained vegetables and turkey.Step 3: Fill two pie crusts with your turkey and vegetable mixture. Carefully top each pie with another pie crust, pinching the sides together.","Bake uncovered in the preheated oven until the pies are golden brown, about 30 minutes. If the tops of the pies are browning too quickly, place a sheet of foil over the pie crusts and continue to bake. Cool for about 10 minutes before serving.This has to be one of the most delicious pot pie recipes I have ever tasted! What a great way to use up that leftover turkey. Another great substitution for turkey would also be to use a Rotisserie chicken. MMmmmm. I will be trying that soon.Have you ever tried a pot pie recipe? What about a Turkey Pot Pie Recipe? Make sure to save this one for those cold and snowy days ahead!JOIN 500,000 SUBSCRIBERS!Join over 500,000 others who follow Pink","When on Social Media, the Pink","When blog, and email. Sign up to receive exclusive bonuses like this FREE Simple Fit Dinners Ebook.Don''t wait! You won''t want to miss a thing.Success! Now check your email to confirm your subscription and download your FREE ebook.There was an error submitting your subscription. Please try again.First Name","Email","Address","Subscribe","Powered by Convert","Kit"]'::jsonb),
  (715419, 'Slow Cooker Spicy Hot Wings', 'Slow Cooker Spicy Hot Wings might be a good recipe to expand your hor d''oeuvre recipe box.  This recipe serves 4 and costs $1.', 'https://img.spoonacular.com/recipes/715419-312x231.jpg', 'https://www.pinkwhen.com/slow-cooker-spicy-hot-wings/', 14, 4, '[{"name":"brown sugar","amount":0.5,"unit":"cups","original":"½ cup brown sugar"},{"name":"cayenne pepper","amount":1,"unit":"tsp","original":"1 tsp cayenne pepper"},{"name":"regular chicken wings","amount":2,"unit":"lb","original":"2 - 4 pounds regular chicken wings"},{"name":"garlic","amount":1,"unit":"Tbsp","original":"1 Tbsp crushed garlic"},{"name":"louisiana hot sauce","amount":0.5,"unit":"cups","original":"½ cup Louisiana Hot sauce"}]'::jsonb, '["Yes, these are called SPICY hot wings for a reason. I like adding the brown sugar to give them a little sweeter taste, but it is by far a delicious spicy recipe more than anything.To get started, mix the brown sugar, crushed garlic, hot sauce, and cayenne pepper into a medium mixing bowl.","Mix well and then set aside.Take the cooking spray and spray the entire inside portion of the slow cooker AND also the wings. (Spraying the wings before you grill, bake, or cook chicken keeps the flavor and makes them super juicy. TRUST ME.)Take the wings and add them into the mixing bowl with your spices and toss to get a good even coat over the wings.","Place in the slow cooker on low for 4 hours. After 4hours, remove carefully and place on a prepared cookie sheet.","Place in the oven under broiler setting for 4-6 minutes, allowing the wings to get a little crisp.","Serve immediately with a little blue cheese dressing and celery."]'::jsonb),
  (997285, 'Shrimp and Asparagus Foil Packs with Garlic Lemon Butter Sauce', 'Shrimp and Asparagus Foil Packs with Garlic Lemon Butter Sauce is a main course that serves 4.  One serving contains 353 calories, 38g of protein, and 20g of fat.', 'https://img.spoonacular.com/recipes/997285-312x231.jpg', 'http://eat-sleep-recipes-repeat.blogspot.com/2017/07/shrimp-and-asparagus-foil-packs-with.html?m=1', 45, 4, '[{"name":"asparagus","amount":1,"unit":"lb","original":"1 lb medium thickness asparagus woody ends trimmed"},{"name":"butter","amount":6,"unit":"Tbsps","original":"6 Tbsp butter diced into small cubes"},{"name":"chicken broth","amount":3,"unit":"Tbsps","original":"3 Tbsp dry white wine or chicken broth"},{"name":"fresh parsley","amount":2,"unit":"Tbsps","original":"2 Tbsp chopped fresh parsley"},{"name":"garlic","amount":4,"unit":"tsps","original":"4 tsp minced garlic"},{"name":"lemon juice","amount":1.5,"unit":"Tbsps","original":"1 1/2 Tbsp fresh lemon juice"},{"name":"lemon zest","amount":2,"unit":"tsps","original":"2 tsp lemon zest"},{"name":"salt and pepper","amount":4,"unit":"servings","original":"Salt and freshly ground black pepper"},{"name":"shrimp","amount":1.5,"unit":"lb","original":"1 1/2 lbs large (21/25) shrimp peeled and deveined*"}]'::jsonb, '["Preheat a grill to medium-high heat (about 400 - 425 degrees).","Cut 4 sheets of 14 by 12-inch heavy duty aluminum foil then lay each piece separately on countertop.","Divide shrimp among packets near center then place asparagus to one side of the shrimp (going the long direction of the foil).","Pour 1/2 Tbsp white wine over each.","Sprinkle over garlic (1 tsp per packet) and lemon zest then season with salt and pepper. Divide butter pieces evenly among packets layering them over the shrimp and asparagus. Wrap packets in and crimp edges together then wrap ends up (don''t wrap too tight - keep a little extra space inside for heat to circulate).","Grill, sealed side upward, until shrimp has cooked through, about 9 - 10 minutes. Carefully unwrap then drizzle with lemon juice (or just serve with lemon wedges for spritzing) and sprinkle with parsley.","Recipe source: Cooking Classy"]'::jsonb),
  (775585, 'Crockpot "Refried" Beans', 'The recipe Crockpot "Refried" Beans can be made in around 45 minutes.  This recipe serves 16.', 'https://img.spoonacular.com/recipes/775585-312x231.jpg', 'http://penniesandpancakes.blogspot.com/2012/09/crockpot-refried-beans-019-per-cup.html?m=1', 45, 16, '[{"name":"pepper","amount":1,"unit":"tsp","original":"1 tsp black pepper"},{"name":"cumin","amount":2,"unit":"tsps","original":"2 tsp cumin"},{"name":"garlic","amount":4,"unit":"Tbsps","original":"4 Tbsp. jarred minced garlic"},{"name":"onion","amount":1,"unit":"large","original":"1 large onion, chopped"},{"name":"pinto beans","amount":2,"unit":"lb","original":"2 lbs pinto beans"},{"name":"up salt","amount":1,"unit":"Tbsp","original":"*Up to 2 1/2 Tbsp salt (This is the absolute max if you don''t pre-soak your beans.)"},{"name":"water","amount":10,"unit":"cups","original":"10 cups hot water"}]'::jsonb, '["Rinse the beans in a colander. Pick out any bad beans.","Combine all the ingredients in the crockpot.","Remove any floating beans. Cover, and cook on HIGH for 4 hours and on LOW for 2 hours.Uncover, and remove extra liquid. Leave enough liquid to reach the desired consistency when the beans are mashed. (We like our beans somewhere between the very-liquidy restaurant style beans, and the canned version of refried beans.)Mash beans with a potato masher to desired consistency.","Serve warm. Store in air-tight containers in the refrigerator and use within 2 weeks, or freeze in ziplock bags for later use."]'::jsonb),
  (715421, 'Cheesy Chicken Enchilada Quinoa Casserole', 'Cheesy Chicken Enchilada Quinoa Casserole might be just the Mexican recipe you are searching for.  One serving contains 594 calories, 34g of protein, and 24g of fat.', 'https://img.spoonacular.com/recipes/715421-312x231.jpg', 'https://www.pinkwhen.com/cheesy-chicken-enchilada-quinoa-casserole/', 30, 4, '[{"name":"avocado","amount":1,"unit":"small","original":"1 small Avocado (chopped)"},{"name":"pepper","amount":0.5,"unit":"tsps","original":"½ tsp black pepper"},{"name":"black beans","amount":15,"unit":"oz","original":"1 (15oz) can of black beans (I like the low sodium version)"},{"name":"canned tomatoes","amount":10,"unit":"oz","original":"1 (10oz) can of tomatoes with green chilis"},{"name":"chili powder","amount":0.5,"unit":"tsps","original":"½ tsp chili powder"},{"name":"quinoa","amount":1,"unit":"cup","original":"1 cup cooked quinoa"},{"name":"cumin","amount":0.5,"unit":"tsps","original":"½ tsp cumin"},{"name":"verde enchilada sauce","amount":10,"unit":"oz","original":"1 (10oz) can of verde enchilada sauce"},{"name":"cilantro","amount":2,"unit":"Tbsps","original":"fresh cilantro (2Tbsp and 2 tsp separated)"},{"name":"green onion tops","amount":4,"unit":"servings","original":"green onion tops (chopped)"},{"name":"roma tomato","amount":1,"unit":"","original":"1 Roma tomato (chopped)"},{"name":"salt","amount":4,"unit":"servings","original":"salt to taste"},{"name":"cheese","amount":2,"unit":"cups","original":"2 cups of shredded cheese (my favorite is the Kraft Mexican 4 cheese blend and one bag equals two cups!)"},{"name":"chicken breast","amount":1,"unit":"","original":"1 boneless skinless chicken breast (boiled and shredded)"},{"name":"corn","amount":15,"unit":"oz","original":"1 (15oz) can of sweet corn (you are only going to use half of the can)"},{"name":"pepper","amount":0.5,"unit":"tsps","original":"½ tsp white pepper"}]'::jsonb, '["To get started, heat your oven to 350 and prepare an 8x8 baking dish. Cook the quinoa according to the instructions. If you haven''t already, boil and shred your chicken breast.In a medium sized mixing bowl add 2 Tbsp cilantro, 1 cup shredded cheese, quinoa, tomatoes with chilis, black beans, half of the can of sweet corn, verde enchilada sauce, cumin, chili powder, white pepper, black pepper, and salt to taste.","Mix everything well, and then pour into the 8 x8 baking dish. Cover with the last cup of cheese and then bake in the oven for 15 minutes.","Remove from oven and allow to cool for 5 minutes. Then top with chopped Roma tomato, chopped avocado, green onion tops, and remaining 2 tsp of cilantro.","Serve immediately."]'::jsonb),
  (715437, 'Homemade King Ranch Chicken Casserole', 'Homemade King Ranch Chicken Casserole is a main course that serves 6.  One serving contains 554 calories, 36g of protein, and 29g of fat.', 'https://img.spoonacular.com/recipes/715437-312x231.jpg', 'https://www.pinkwhen.com/king-ranch-chicken-casserole/', 65, 6, '[{"name":"butter","amount":0.25,"unit":"cups","original":"¼ cup butter"},{"name":"chicken breasts","amount":2,"unit":"","original":"2 cooked and cubed chicken breasts"},{"name":"cream of chicken soup","amount":10.5,"unit":"oz","original":"1 (10.5oz) can Cream of Chicken Soup"},{"name":"cream of mushroom soup","amount":10.5,"unit":"oz","original":"1 (10.5oz) can Cream of Mushroom Soup"},{"name":"tomatoes and chilis","amount":20,"unit":"oz","original":"2 (10oz) cans Tomatoes and Green Chilis"},{"name":"flour tortillas","amount":10,"unit":"","original":"1 (10 count) package flour tortillas (torn into bite sized pieces)"},{"name":"mexican cheddar jack cheese","amount":2,"unit":"cups","original":"2 cup package Mexican Cheddar Jack shredded cheese"},{"name":"onion","amount":1,"unit":"medium","original":"1 medium onion"}]'::jsonb, '["If you haven''t already, cook your chicken breasts by boiling them in water for 20 minutes, or until juices run clear when cut into. Then cube and set aside.Preheat the oven to 35","Chop the onion into small pieces and saute in  cup butter over medium heat for 5 minutes or until slightly translucent. Turn heat down to low and add both cans of soup, stirring until mixed well.","Remove from heat and set aside.In a prepared 9 x 13 baking dish place a layer of tortillas to cover the bottom of the dish.","Add a thin layer of tomatoes and green chilis, a thin layer of the soup mixture, a thin layer of chicken, and top with cheese.","Add another thin layer of tortillas, tomatoes and green chilis, soup mixture, chicken, and cheese. Keep doing the layers until you run out of space, finally covering the dish with the remaining cheese.","Bake in the preheated oven on 350 for 45 minutes, or until cheese is turned a golden brown. Allow to cool before serving."]'::jsonb),
  (715394, 'Chicken Enchilada Casserole', 'Chicken Enchilada Casserole might be just the main course you are searching for.  This recipe makes 8 servings with 325 calories, 26g of protein, and 12g of fat each.', 'https://img.spoonacular.com/recipes/715394-312x231.jpg', 'https://www.pinkwhen.com/chicken-enchilada-casserole-recipe/', 45, 8, '[{"name":"verde enchilada sauce","amount":20,"unit":"oz","original":"2 10oz cans verde enchilada sauce"},{"name":"cheese","amount":2,"unit":"cups","original":"2 cups shredded cheese"},{"name":"chicken pre","amount":1,"unit":"lb","original":"1 lb shredded chicken pre cooked"},{"name":"canned tomatoes","amount":10,"unit":"oz","original":"1 10oz can tomatoes with green chilis"},{"name":"refried beans","amount":15,"unit":"oz","original":"1 15oz can refried beans"},{"name":"flour tortillas torn into bite sized pieces","amount":6,"unit":"","original":"6-8 flour tortillas torn into bite sized pieces"},{"name":"green onion tops optional","amount":8,"unit":"servings","original":"green onion tops optional"}]'::jsonb, '["Heat oven to 37","Prepare a 9 x 13 baking dish and begin by placing a layer of tortillas on the bottom of the dish.","Then add a layer of chicken and 1/4 a cup of the shredded cheese.","Add on half a can of tomatoes and green chilies and one can of the verde enchilada sauce.","Finish the layer with a half a can of the refried beans.","Then cover with another layer of flour tortilla pieces, and start the layering process again.","Once you are finished layering, cover the top with the remaining shredded cheese.","Cover with foil, and then bake in the oven for 30 minutes.","Remove the foil, add a few green onion tops, and bake for an additional 5 minutes until the cheese is melted and bubbly. Allow to sit for 10-15 minutes to allow to cool before serving. Serving any sooner may give you a soupy, but still delicious dinner."]'::jsonb),
  (715544, 'Brown Butter Twice Baked Sweet Potatoes', 'The recipe Brown Butter Twice Baked Sweet Potatoes can be made in about 1 hour and 35 minutes.  Watching your figure?', 'https://img.spoonacular.com/recipes/715544-312x231.jpg', 'https://www.pinkwhen.com/brown-butter-twice-baked-sweet-potatoes/', 95, 4, '[{"name":"avocados","amount":2,"unit":"","original":"2 very ripe avocados, pitted and skins removed"},{"name":"buttermilk","amount":2,"unit":"Tbsps","original":"2 tablespoons buttermilk"},{"name":"bacon","amount":4,"unit":"strips","original":"4 strips of bacon, cooked until crisp and chopped"},{"name":"parsley","amount":0.25,"unit":"cups","original":"1/4 cup fresh parsley, chopped"},{"name":"goat''s cheese","amount":6,"unit":"oz","original":"6 ounces goat''s cheese, crumbled"},{"name":"salt and pepper","amount":4,"unit":"servings","original":"salt and black pepper"},{"name":"cream","amount":0.5,"unit":"cups","original":"1/2 cup sour cream (plain Greek yogurt may be substituted)"},{"name":"sweet potatoes","amount":4,"unit":"medium","original":"4 medium sweet potatoes"},{"name":"butter","amount":6,"unit":"Tbsps","original":"6 tablespoons unsalted butter"}]'::jsonb, '["Preheat your oven to 400 degrees F. Poke your sweet potatoes with a fork and place them directly on the rack of your oven.","Place a piece of foil on the rack below to reduce mess.","Bake the sweet potatoes for 45-50 minutes or until tender. Times may vary depending on how hot your oven gets.","Remove the potatoes from the oven and let stand at room temperature until they are cool enough to handle, about 20-30 minutes. Leave the oven on.While your potatoes are cooling, melt the butter over medium heat. Continue to cook the butter, stirring frequently, until brown bits begin to form on the bottom of the pan, about 5-6 minutes. Pay close attention as the butter can quickly go from brown to burnt in a matter of seconds. Once you see the brown bits forming and a nutty aroma fills the air, pull the butter from the heat immediately. Set aside.","Cut the tops off of the sweet potatoes, lengthwise. Scoop the sweet potato flesh into a medium bowl, leaving the skins in tact. To the bowl, add the brown butter, 2 tablespoons of the fresh parsley, 3/4 of the chopped bacon, and 4 ounces of the goats cheese.","Sprinkle with salt and black pepper to taste and mash the ingredients together until combined. Scoop the filling back into the sweet potatoes.","Place the potatoes on a baking sheet that has been lined with foil or parchment paper.","Place them back in the oven to bake for 25 minutes.While your potatoes are baking for a second time, prepare your avocado cream. In the bowl of your food processor or blender, combine the avocados, sour cream and buttermilk.","Add a dash of salt and pepper and pulse until completely smooth and creamy.Once your potatoes have baked, remove from oven.","Sprinkle on the remaining parsley, bacon and goats cheese.","Drizzle with avocado cream and serve immediately.Enjoy!I hope you enjoy this recipe for brown butter twice baked sweet potatoes!"]'::jsonb),
  (715562, 'Loaded Baked Potato Soup', 'Loaded Baked Potato Soup might be just the main course you are searching for.  This recipe serves 8.', 'https://img.spoonacular.com/recipes/715562-312x231.jpg', 'https://www.pinkwhen.com/loaded-baked-potato-soup/', 60, 8, '[{"name":"bacon bits","amount":8,"unit":"servings","original":"bacon bits"},{"name":"baking potatoes","amount":8,"unit":"medium","original":"8 medium baking potatoes (peeled and cubed)"},{"name":"butter","amount":0.5,"unit":"cups","original":"½ cup butter"},{"name":"flour","amount":0.5,"unit":"cups","original":"½ cup flour"},{"name":"milk","amount":8,"unit":"cups","original":"8 cups milk"},{"name":"salt and pepper","amount":8,"unit":"servings","original":"salt and pepper to taste"},{"name":"cheddar cheese","amount":2,"unit":"cups","original":"2 cups shredded cheddar cheese"},{"name":"cream","amount":8,"unit":"oz","original":"8 oz. container of sour cream"},{"name":"onion","amount":0.5,"unit":"medium","original":"½ medium chopped white onion"}]'::jsonb, '["Place a large pot of water on the stove and add in the peeled and cubed potatoes. Get the water up to a boil, and then boil for 20 minutes, or until potatoes are cooked.","Remove from heat and drain water.","Place to the side.In a medium pot over medium-high heat melt butter and sautee onion for 6 minutes.","Add in the flour and using a whisk, mix well for 30 seconds to one minute.Gradually start whisking in the milk, about ½ cup to a cup at a time, constantly stirring. You want to keep whisking and adding milk and stirring. Bring to a boil, and then turn heat down to medium and allow the mixture to simmer for 8-10 minutes until thickened.Stir in the potatoes and cook for an additional 5 minutes.","Add in the cheese, salt and pepper, sour cream and stir well.","Remove from heat and allow to cool slightly before serving.Top with additional sour cream, cheese, and bacon bits if desired."]'::jsonb),
  (716426, 'Cauliflower, Brown Rice, and Vegetable Fried Rice', 'The recipe Cauliflower, Brown Rice, and Vegetable Fried Rice is ready in around 30 minutes and is definitely a great gluten free, dairy free, lacto ovo vegetarian, and vegan option for lovers of Chinese food.  This recipe makes 8 servings with 248 calories, 7g of protein, and 13g of fat each.', 'https://img.spoonacular.com/recipes/716426-312x231.jpg', 'https://fullbellysisters.blogspot.com/2012/01/cauliflower-fried-rice-more-veggies.html', 30, 8, '[{"name":"grapeseed oil","amount":2,"unit":"Tbsps","original":"2 tablespoons grapeseed oil"},{"name":"coconut oil","amount":2,"unit":"Tbsps","original":"2 tablespoons coconut oil"},{"name":"scallions","amount":7,"unit":"","original":"7 scallions, chopped (keep white/light green ends separate from dark green tops)"},{"name":"garlic","amount":5,"unit":"cloves","original":"5 cloves of garlic, chopped"},{"name":"cauliflower","amount":1,"unit":"head","original":"head of cauliflower, raw"},{"name":"brown rice","amount":3,"unit":"cups","original":"3 cups of cooked brown rice, cold"},{"name":"broccoli","amount":2,"unit":"cups","original":"2 cups cooked broccoli, chopped small"},{"name":"peas","amount":1,"unit":"cup","original":"1 cup frozen peas"},{"name":"soy sauce","amount":3,"unit":"Tbsps","original":"3 T reduced-sodium soy sauce"},{"name":"sesame oil","amount":2,"unit":"tsps","original":"2 teaspoons toasted sesame oil"},{"name":"sesame seeds","amount":8,"unit":"servings","original":"toasted sesame seeds, optional"},{"name":"additional scallion tops","amount":8,"unit":"servings","original":"additional chopped scallion tops for garnish"},{"name":"salt","amount":8,"unit":"servings","original":"salt, to taste"}]'::jsonb, '["Remove the cauliflower''s tough stem and reserve for another use. Using a food processor, pulse cauliflower florets until they resemble rice or couscous. You should end up with around four cups of \"cauliflower rice.\"","Heat 1T butter and 1T oil in a large skillet over medium heat.","Add garlic and the white and light green pieces of scallion. Sauté about a minute.","Add the cauliflower to the pan. Stir to coat with oil, then spread out in pan and let sit; you want it cook a bit and to caramelize (get a bit brown), which will bring out the sweetness. After a couple of minutes, stir and spread out again.","Add cold rice (it separates easily, so it won''t clump up during cooking), plus the additional grapeseed and coconut oil or butter. Raise heat to medium-high. Toss everything together and, again, spread the mixture out over the whole pan and press a bit into the bottom.","Let it sit for about two minutes—so the rice can get toasted and a little crispy.","Add the peas and broccoli and stir again.","Drizzle soy sauce and toasted sesame oil over rice.Cook for another minute or so and turn off heat.","Add chopped scallion tops and toss.I like to toast some sesame seeds in a dry pan; I sprinkle these and some more raw, chopped scallion over the top of the rice for added flavor and crunch.Season to taste with salt and, if you''d like, more soy sauce. Keep in mind that if you''re serving this with something salty and saucy (ie. teriyaki chicken) you may want to hold off on adding too much salt to the fried rice."]'::jsonb),
  (715541, 'Pink Lemonade Crinkle Cookies', 'Pink Lemonade Crinkle Cookies might be a good recipe to expand your dessert recipe box.  This recipe serves 5.', 'https://img.spoonacular.com/recipes/715541-312x231.jpg', 'https://www.pinkwhen.com/pink-lemonade-crinkle-cookies/', 45, 5, '[{"name":"baking powder","amount":0.25,"unit":"tsps","original":"1/4 tsp Baking Powder"},{"name":"baking soda","amount":0.25,"unit":"tsps","original":"1/4 tsp Baking Soda"},{"name":"butter","amount":0.75,"unit":"cups","original":"3/4 C Butter"},{"name":"cornstarch","amount":0.5,"unit":"cups","original":"1/2 C Cornstarch"},{"name":"egg","amount":1,"unit":"","original":"1 Egg"},{"name":"flour","amount":1.5,"unit":"cups","original":"1 1/2 C All-Purpose Flour"},{"name":"pink food coloring","amount":1,"unit":"drop","original":"1 drop of pink food coloring (optional)"},{"name":"pink lemonade kool-aid","amount":0.5,"unit":"tsps","original":"1/2 – 3/4 tsp Pink Lemonade Kool-Aid"},{"name":"powdered sugar","amount":0.25,"unit":"cups","original":"1/4 C Powdered Sugar"},{"name":"sugar","amount":1.25,"unit":"cups","original":"1 1/4 C Sugar"}]'::jsonb, '["Prepare a cookie sheet by greasing with non-stick cooking spray. Preheat oven to 35","Cream butter and sugar together in your mixer, scraping the sides of your bowl.","Add your egg and mix well.","Mix in baking powder, baking soda, Kool-Aid and cornstarch. Once its well mixed (the Kool-Aid will be mixed once it turns your dough pink), add a drop of pink food coloring, if more color is desired. Next, start adding your flour a half cup at a time until its all added.","Roll the dough into walnut-sized balls and roll in the powder sugar, giving them a light coating.","Place 2 apart on a room-temp baking sheet (let your sheet cool in between batches if you are reusing the same one).","Bake in the oven 9-10 minutes, they wont brown too much, so watch them closely. Over-baking will make them hard and crunchy!I hope you enjoy these! I will be baking another batch soon, we have a neighborhood barbecue coming up and I know these will be perfect!Want more Whistle and Ivy? Subscribe here! And dont forget to follow on Instagram and Pinterest.You may also like these Avocado Mint Chocolate Sugar Cookies or this Honey Kool-Aid Taffy","Until next time,JOIN 500,000 SUBSCRIBERS!Join over 500,000 others who follow Pink","When on Social Media, the Pink","When blog, and email. Sign up to receive exclusive bonuses like this FREE Simple Fit Dinners Ebook.Don''t wait! You won''t want to miss a thing.Success! Now check your email to confirm your subscription and download your FREE ebook.There was an error submitting your subscription. Please try again.First Name","Email","Address","Subscribe","Powered by Convert","Kit"]'::jsonb),
  (715391, 'Slow Cooker Chicken Taco Soup', 'Forget going out to eat or ordering takeout every time you crave Mexican food.  Try making Slow Cooker Chicken Taco Soup at home.', 'https://img.spoonacular.com/recipes/715391-312x231.jpg', 'https://www.pinkwhen.com/slow-cooker-chicken-taco-soup-recipe/', 485, 6, '[{"name":"black beans","amount":15,"unit":"oz","original":"1 (15 oz.) can black beans"},{"name":"tomatoes","amount":20,"unit":"oz","original":"2 (10 oz.) cans diced tomatoes with green chilis"},{"name":"canned tomatoes","amount":15,"unit":"oz","original":"1 (15 oz.) can diced tomatoes"},{"name":"chili beans","amount":15,"unit":"oz","original":"1 (15 oz.) can chili beans"},{"name":"kernal corn","amount":15,"unit":"oz","original":"1 (15 oz.) can whole kernal corn"},{"name":"onion","amount":1,"unit":"large","original":"1 large red onion (finely chopped)"},{"name":"chicken breasts","amount":3,"unit":"","original":"3 boneless skinless chicken breasts (cut into 1\" cubes)"}]'::jsonb, '["Once you have all of your ingredients added, allow it to cook all day for 8 hours on low. If you are wanting to make this a little faster, turn it on high and cook for 4 hours.When your Chicken Taco Soup is ready to serve, add in some crushed tortilla shells, shredded cheddar cheese, and a little sour cream."]'::jsonb),
  (715545, 'How to Make the Best Chicken Jambalaya', 'You can never have too many Cajun recipes, so give How to Make the Best Chicken Jambalayan a try.  This main course has 450 calories, 26g of protein, and 21g of fat per serving.', 'https://img.spoonacular.com/recipes/715545-312x231.jpg', 'https://www.pinkwhen.com/chicken-and-sausage-jambalaya/', 55, 8, '[{"name":"▢ butter","amount":2,"unit":"Tbsps","original":"▢ 2 tbsp unsalted butter"},{"name":"▢ sausage","amount":1,"unit":"lb","original":"▢ 1 lb sliced sausage"},{"name":"▢ chicken breasts","amount":1,"unit":"lb","original":"▢ 1 lb boneless skinless chicken breasts cut into bite sized pieces"},{"name":"▢ onion","amount":1,"unit":"cup","original":"▢ 1 cup yellow onion chopped"},{"name":"▢ celery","amount":1,"unit":"cup","original":"▢ 1 cup celery chopped"},{"name":"▢ bell pepper","amount":0.5,"unit":"cups","original":"▢ 1/2 cup bell pepper chopped"},{"name":"▢ garlic","amount":1,"unit":"Tbsp","original":"▢ 1 tbsp minced garlic"},{"name":"▢ tomato sauce","amount":1,"unit":"cup","original":"▢ 1 cup tomato sauce"},{"name":"▢ tomatoes","amount":14.5,"unit":"oz","original":"▢ 14.5 oz diced tomatoes"},{"name":"▢ chicken stock","amount":2.5,"unit":"cups","original":"▢ 2 1/2 cups chicken stock"},{"name":"▢ rice","amount":1.5,"unit":"cups","original":"▢ 1 1/2 cups rice uncooked and rinsed"},{"name":"▢ 2 bay","amount":1,"unit":"leaf","original":"▢ 2 bay leaves whole"},{"name":"▢ ground pepper","amount":2,"unit":"tsps","original":"▢ 2 tsp ground black pepper"},{"name":"▢ salt","amount":1,"unit":"tsp","original":"▢ 1 tsp salt"},{"name":"▢ pepper","amount":1,"unit":"tsp","original":"▢ 1 tsp white pepper"},{"name":"▢ thyme","amount":1,"unit":"tsp","original":"▢ 1 tsp thyme dried"},{"name":"▢ pepper flakes","amount":1,"unit":"tsp","original":"▢ 1 tsp red pepper flakes"},{"name":"▢ sage","amount":0.5,"unit":"tsps","original":"▢ 1/2 tsp sage"}]'::jsonb, '["Combine the creole seasoning ingredients in a small bowl and set aside.","Melt butter in a large dutch oven over medium-high heat.","Add the sausage until it starts to brown, about 3 minutes.","Add the chicken and continue to cook until brown, about 3-5 minutes. Stir frequently.","Turn the stove top down to medium heat.","Preheat your oven to 350 degrees.","Stir in the seasoning mix of cajun spices and 1/2 of the chopped onion, celery, green bell pepper, and garlic. Cook until vegetables get tender, about 3-5 minutes. Stir frequently and scrape the bottom of the pot frequently.","Stir in the tomato sauce and cook for about one minute.","Stir in the remaining onion, celery, bell pepper, garlic, and the diced tomatoes then remove from heat.","Stir in the rice and chicken stock, mix the ingredients well.","Bake uncovered in the oven at 350 degrees for one hour or until the rice is tender but still has a little crunch.","Remove from the oven, add the bay leaves and stir well.","Allow the dish to cool for five minutes before serving. OPTIONAL: Top with green onions before serving."]'::jsonb),
  (715569, 'Strawberry Cheesecake Chocolate Crepes', 'Need a lacto ovo vegetarian breakfast?  Strawberry Cheesecake Chocolate Crepes could be an excellent recipe to try.', 'https://img.spoonacular.com/recipes/715569-312x231.jpg', 'https://www.pinkwhen.com/strawberry-cheesecake-chocolate-crepes/', 40, 4, '[{"name":"cream cheese","amount":8,"unit":"oz","original":"8 oz cream cheese"},{"name":"strawberries","amount":1.25,"unit":"cups","original":"1 1/4 cup diced strawberries"},{"name":"vanilla extract","amount":1,"unit":"tsp","original":"1 tsp vanilla extract"},{"name":"lemon juice","amount":1,"unit":"tsp","original":"1 tsp lemon juice"},{"name":"granulated sugar","amount":2,"unit":"Tbsps","original":"2 tbsp granulated sugar"},{"name":"flour","amount":1.5,"unit":"cups","original":"1 1/2 cups all-purpose flour"},{"name":"cocoa powder","amount":0.25,"unit":"cups","original":"1/4 cup cocoa powder unsweetened"},{"name":"kosher salt","amount":0.125,"unit":"tsps","original":"1/8 tsp kosher salt"},{"name":"eggs","amount":3,"unit":"","original":"3 eggs"},{"name":"milk","amount":1.25,"unit":"cups","original":"1 1/4 cups milk"},{"name":"water","amount":0.25,"unit":"cups","original":"1/4 cup water"},{"name":"butter","amount":4,"unit":"Tbsps","original":"4 tbsp unsalted butter melted"},{"name":"vanilla extract","amount":0.5,"unit":"tsps","original":"1/2 tsp vanilla extract"}]'::jsonb, '["How to Make Strawberry Creme Cheese Filling","Add cream cheese, strawberries, vanilla extract, lemon juice, and granulated sugar into a medium-sized mixing bowl.","Use a hand mixer, wooden spoon, or spatula to mix ingredients.","Mix until smooth.","Set aside.","How to Blend Chocolate Crepes Ingredients","Combine flour, sugar, cocoa powder, salt, and eggs to a food processor or blender.","If using a food processor, keep it running as you add milk and water. Continue to pulse intil blended well.","Pour in melted butter and vanilla extract.","Set bowl aside.","How to Make Chocolate Crepes","Heat crepe pan or 8\"-10\" omelet pan over medium heat.","Pour 1/4 cup of batter directly into the middle of the pan and swirl to cover the bottom.","Cook the crepe for 2-3 minutes or until the bottom is light brown and the edges are completely set.","Flip the crepe over and cook for an additional minute.","Transfer to a serving platter and repeat for the rest of the batter."]'::jsonb),
  (715415, 'Red Lentil Soup with Chicken and Turnips', 'Red Lentil Soup with Chicken and Turnips might be a good recipe to expand your main course repertoire.  This recipe serves 8 and costs $3.', 'https://img.spoonacular.com/recipes/715415-312x231.jpg', 'https://www.pinkwhen.com/red-lentil-soup-with-chicken-and-turnips/', 55, 8, '[{"name":"additional toppings: avocado","amount":8,"unit":"servings","original":"additional toppings: diced avocado, micro greens, chopped basil)"},{"name":"carrots","amount":3,"unit":"medium","original":"3 medium carrots, peeled and diced"},{"name":"celery stalks","amount":3,"unit":"","original":"3 celery stalks, diced"},{"name":"chicken breast","amount":2,"unit":"cups","original":"2 cups fully-cooked chicken breast, shredded (may be omitted for a vegetarian version)"},{"name":"flat leaf parsley","amount":0.5,"unit":"cups","original":"½ cup flat leaf Italian parsley, chopped (plus extra for garnish)"},{"name":"garlic","amount":6,"unit":"cloves","original":"6 cloves of garlic, finely minced"},{"name":"olive oil","amount":2,"unit":"Tbsps","original":"2 tablespoons olive oil"},{"name":"canned tomatoes","amount":28,"unit":"oz","original":"28 ounce-can plum tomatoes, drained and rinsed, chopped"},{"name":"lentils","amount":2,"unit":"cups","original":"2 cups dried red lentils, rinsed"},{"name":"salt and pepper","amount":8,"unit":"servings","original":"salt and black pepper, to taste"},{"name":"turnip","amount":1,"unit":"large","original":"1 large turnip, peeled and diced"},{"name":"vegetable stock","amount":8,"unit":"cups","original":"8 cups vegetable stock"},{"name":"onion","amount":1,"unit":"medium","original":"1 medium yellow onion, diced"}]'::jsonb, '["To a large dutch oven or soup pot, heat the olive oil over medium heat.","Add the onion, carrots and celery and cook for 8-10 minutes or until tender, stirring occasionally.","Add the garlic and cook for an additional 2 minutes, or until fragrant. Season conservatively with a pinch of salt and black pepper.To the pot, add the tomatoes, turnip and red lentils. Stir to combine. Stir in the vegetable stock and increase the heat on the stove to high. Bring the soup to a boil and then reduce to a simmer. Simmer for 20 minutes or until the turnips are tender and the lentils are cooked through.","Add the chicken breast and parsley. Cook for an additional 5 minutes. Adjust seasoning to taste.","Serve the soup immediately garnished with fresh parsley and any additional toppings. Enjoy!"]'::jsonb),
  (715381, 'Creamy Lime Pie Square Bites', 'Creamy Lime Pie Square Bites might be just the dessert you are searching for.  One serving contains 631 calories, 8g of protein, and 33g of fat.', 'https://img.spoonacular.com/recipes/715381-312x231.jpg', 'https://www.pinkwhen.com/creamy-lime-pie-square-bites/', 45, 2, '[{"name":"all purpose flour","amount":0.6666667,"unit":"cups","original":"2/3 cup all purpose flour"},{"name":"graham cracker crumbs","amount":1,"unit":"cup","original":"1 cup crushed graham cracker crumbs"},{"name":"lime zest","amount":2,"unit":"drop","original":"2 drop Lime essential oil (this is the brand I use) OR if not using essential oils, use 1 Tbsp grated lime zest."},{"name":"sugar","amount":2,"unit":"Tbsps","original":"2 tbsp sugar"},{"name":"butter","amount":5,"unit":"Tbsps","original":"5 Tbsp unsalted butter (softened)"}]'::jsonb, '["Preheat oven to 35","Cover an 88 glass square dish with foil.","Whisk together all of your crust ingredients until it becomes a grainy consistency. Take a spoon and press the graham crust into the foil making sure all of the edges and bottom are completely covered.","Place into the oven and bake for 10-15 minutes until browned.","Remove from oven and allow to cool for about an hour.For the filling, add all of your ingredients into a medium bowl and mix well for about 30 minutes, and then for 3 minutes on low.","Place into the graham cracker crust, making sure all of the edges are filled.","Bake in the oven for about 5-10 minutes, and then remove.","Place onto a cooling rack for about 15 minutes, and then chill in the refrigerator for remaining 45 minutes to set.To serve, remove carefully from dish with foil and cut into bite sized squares.Looking for other ways to use Lime Essential Oil? A great group of bloggers and myself got together so we could share our favorite recipes to use with Lime. You dont have to use essential oils in order to make this delicious dessert, but if you have on hand, give it a try! You can find all of the other great Lime recipes below. Leave me a comment if you make these Creamy Lime Pie Square Bites and tell me if you love them as much as we do!If you have ever wanted to start using essential oils, you can read all about WHY I love to use mine here. Want to use Lime in a few different recipes? Check these additional recipes out.Coconut Lime Spritzer // Blackberry Lime Margaritas // Strawberry Limeade","Cherry Lime Chia Energy Bars // Strawberry Margarita Cheesecake // Creamy Lime Pie Bites","Margarita Crepe Cake //Edible Watermelon Bowl // Margarita Cookies","Southwestern Black Bean & Corn Salad // Lime Cheesecake Shooters","Not all essential oils are edible. Due to lack of purity, 98% of essential oils sold should NOT be ingested. An edible essential oil will be labeled therapeutic-grade and have a Supplement Facts box on the label showing the nutritional value  do NOT use just any brand of essential oil for cooking/flavoring foods. Be sure to use pure oils from reliable sources, not synthetic scents or flavorings.JOIN 500,000 SUBSCRIBERS!Join over 500,000 others who follow Pink","When on Social Media, the Pink","When blog, and email. Sign up to receive exclusive bonuses like this FREE Simple Fit Dinners Ebook.Don''t wait! You won''t want to miss a thing.Success! Now check your email to confirm your subscription and download your FREE ebook.There was an error submitting your subscription. Please try again.First Name","Email","Address","Subscribe","Powered by Convert","Kit"]'::jsonb),
  (715452, 'Delicious Triple Chocolate Bundt Cake', 'Delicious Triple Chocolate Bundt Cake might be a good recipe to expand your dessert recipe box.  This recipe makes 6 servings with 582 calories, 5g of protein, and 30g of fat each.', 'https://img.spoonacular.com/recipes/715452-312x231.jpg', 'https://www.pinkwhen.com/delicious-triple-chocolate-bundt-cake/', 55, 6, '[{"name":"devil''s food cake mix","amount":1,"unit":"","original":"1 devil''s food cake mix"},{"name":"chocolate fudge pudding mix","amount":1,"unit":"small","original":"1 small box chocolate fudge pudding mix"},{"name":"milk chocolate chips","amount":1,"unit":"cup","original":"1 cup milk chocolate chips"},{"name":"cream","amount":1,"unit":"cup","original":"1 cup sour cream"}]'::jsonb, '["Preheat your oven to 350 degrees.","Mix the cake as directed.","Add the pudding and sour cream.","Mix well. Stir in chocolate chips.Spray a bundt pan generously with non-stick spray and then coat with flour.","Bake for 50 minutes. Cool for 5 minutes and dump onto the cooling rack.Optional: serve warm sliced with a drizzle of Dove milk chocolate ice cream topping and a scoop of vanilla ice cream."]'::jsonb),
  (715550, 'Old Fashioned Vanilla Buttercream Frosting', 'Old Fashioned Vanilla Buttercream Frosting is a frosting that serves 8.  Watching your figure?', 'https://img.spoonacular.com/recipes/715550-312x231.jpg', 'https://www.pinkwhen.com/old-fashioned-vanilla-buttercream-frosting/', 5, 8, '[{"name":"solid vegetable shortening","amount":0.5,"unit":"cups","original":"1/2 cup solid vegetable shortening"},{"name":"butter","amount":0.5,"unit":"cups","original":"1/2 cup softened butter"},{"name":"vanilla","amount":1.5,"unit":"tsps","original":"1 1/2 tsp vanilla"},{"name":"confectioners sugar","amount":5,"unit":"cups","original":"5 cups confectioners sugar"},{"name":"milk","amount":3,"unit":"Tbsps","original":"3 Tbsp milk"}]'::jsonb, '["Buttercream Icing Recipe","In a large mixing bowl cream butter and shortening with electric mixer.","Add vanilla.","Gradually add in sifted confectioners sugar, one cup at a time beating on medium speed.","Scrape sides and bottom of bowl often. When all of the sugar has been mixed in, icing will appear dry.","Add milk and beat at medium speed for 3 minutes.","Keep icing covered with a damp cloth until ready to decorate. For best results, keep icing bowl in refrigerator when not using.","Icing can be stored in an air tight container for up to a week. Just re-whip it in your mixer before using. Makes 3 1/2 cups."]'::jsonb),
  (715392, 'Easy Slow Cooker Chicken Tortilla Soup', 'Easy Slow Cooker Chicken Tortilla Soup takes approximately 6 hours and 10 minutes from beginning to end.  One portion of this dish contains approximately 32g of protein, 4g of fat, and a total of 283 calories.', 'https://img.spoonacular.com/recipes/715392-312x231.jpg', 'https://www.pinkwhen.com/chicken-tortilla-soup-slow-cooker/', 370, 8, '[{"name":"chicken breast","amount":2,"unit":"lb","original":"2 pounds chicken breast"},{"name":"onion","amount":1,"unit":"medium","original":"1 medium onion (finely chopped)"},{"name":"chili powder","amount":2,"unit":"tsps","original":"2 teaspoon chili powder"},{"name":"tomatoes","amount":28,"unit":"oz","original":"28 ounces crushed tomatoes"},{"name":"chicken broth","amount":24,"unit":"oz","original":"24 ounces chicken broth"},{"name":"kernel corn","amount":15,"unit":"oz","original":"15 ounces kernel corn (drained)"},{"name":"chilis","amount":4,"unit":"oz","original":"4 ounces green chilis (diced)"},{"name":"black beans","amount":15,"unit":"oz","original":"15 ounces black beans (drained)"},{"name":"cilantro","amount":0.25,"unit":"cups","original":"1/4 cup cilantro (freshly chopped)"}]'::jsonb, '["Add all of your ingredients into the slow cooker and then cook on low for 6 hours.","Once finished cooking, scoop into serving bowls and serve with tortilla chips, sour cream, cheese, avocado, or any of your favorite toppings."]'::jsonb),
  (715397, 'Cheesy Chicken and Rice Casserole', 'Cheesy Chicken and Rice Casserole might be just the main course you are searching for.  This recipe makes 6 servings with 464 calories, 31g of protein, and 28g of fat each.', 'https://img.spoonacular.com/recipes/715397-312x231.jpg', 'https://www.pinkwhen.com/cheesy-chicken-and-rice-casserole-bake/', 60, 6, '[{"name":"grilled chicken breasts","amount":2,"unit":"","original":"2 grilled chicken breasts"},{"name":"rice","amount":2,"unit":"cups","original":"2 cups rice (cooked)"},{"name":"cream cheese","amount":8,"unit":"oz","original":"1 8oz package cream cheese"},{"name":"cream of mushroom soup","amount":10,"unit":"oz","original":"1 10oz. can cream of mushroom soup"},{"name":"bell pepper","amount":1,"unit":"medium","original":"1 medium green pepper"},{"name":"monterrey jack cheese","amount":1.5,"unit":"cups","original":"1½ cup shredded Monterrey Jack cheese"},{"name":"onion","amount":0.5,"unit":"","original":"½ red onion"},{"name":"salt and pepper","amount":6,"unit":"servings","original":"Salt and pepper to taste"},{"name":"country crock buttery spread","amount":2,"unit":"Tbsps","original":"2 Tbsp Country crock buttery spread"}]'::jsonb, '["Heat your oven to 350.Take your 2 grilled chicken breasts and allow them to slightly cool. Shred chicken breasts and place to the side in a mixing bowl.Finely chop your pepper and onion and saut in 2 Tbsp Country Crock for 5 minutes until soft.","Add cream cheese into the onion and pepper and mix well.","Pour into the large bowl with chicken.","Mix in rice, hot sauce, cream of mushroom soup,  cup Monterrey Jack cheese, and salt and pepper.","Mix well.","Pour mixture in a 9 x 13 dish, and cover with remaining cheese and add salt and pepper to taste.","Bake for 30 minutes. Allow to cool for 5 minutes before serving."]'::jsonb),
  (715439, 'OREO Cookie Balls – Snowman', 'If you want to add more lacto ovo vegetarian recipes to your recipe box, OREO Cookie Balls – Snowman might be a recipe you should try.  This recipe serves 12 and costs $3.', 'https://img.spoonacular.com/recipes/715439-312x231.jpg', 'https://www.pinkwhen.com/oreo-cookie-balls-snowman-recipe/', 75, 12, '[{"name":"oreo cookies","amount":1,"unit":"pkg","original":"1 package OREO Cookies"},{"name":"cream cheese","amount":8,"unit":"oz","original":"1 8 oz package Cream Cheese softened"},{"name":"bakers chocolate","amount":4,"unit":"pkg","original":"4 packages Bakers Chocolate"},{"name":"rolo chocolate candy","amount":1,"unit":"pkg","original":"1 package Rolo chocolate candy"},{"name":"gel icing","amount":12,"unit":"servings","original":"black gel icing"},{"name":"orange gel icing","amount":12,"unit":"servings","original":"orange gel icing"},{"name":"additional supplies to decorate snowmen","amount":1,"unit":"serving","original":"Additional supplies to decorate snowmen"},{"name":"additional supplies to decorate snowmen","amount":12,"unit":"servings","original":"Additional supplies to decorate snowmen"}]'::jsonb, '["Take the entire package of OREO Cookies (filling and all) and crush them in a large gallon ziplock bag.","Empty cookie crumbs into large mixing bowl.","Place cream cheese in large mixing bowl.","Mix well on medium speed.","Use a 1\" cookie scoop and create round balls with palms of hands.","Place on a cookie sheet.","Place cookie balls in freezer for about 10 minutes.","Melt","Baker''s Chocolate per instructions.","Dip Cookie Balls into chocolate and then place on a wax paper covered cookie sheet.","Place in the refrigerator for an hour to harden.","Take icing and dab a bit on a Rolo candy and place on the top of the cookie ball. Use the gel icing to create eyes, nose, and mouth.","Add a dab of icing to snowflake and attach to the Rolo for decoration."]'::jsonb),
  (775666, 'Easy Homemade Apple Fritters', 'Easy Homemade Apple Fritters might be just the breakfast you are searching for.  One portion of this dish contains approximately 2g of protein, 1g of fat, and a total of 148 calories.', 'https://img.spoonacular.com/recipes/775666-312x231.jpg', 'https://www.recipeoftoday.com/2015/05/easy-homemade-apple-fritters.html?m=1', 30, 12, '[{"name":"all purpose flour","amount":1,"unit":"cup","original":"1 cup all purpose flour"},{"name":"apple","amount":1,"unit":"cup","original":"1 cup chopped apple"},{"name":"baking powder","amount":1.5,"unit":"tsps","original":"1 1/2 teaspoons baking powder"},{"name":"cinnamon","amount":1,"unit":"tsp","original":"1 teaspoon cinnamon"},{"name":"egg","amount":1,"unit":"","original":"1 egg"},{"name":"milk","amount":0.33333334,"unit":"cups","original":"1/3 cup milk"},{"name":"milk","amount":1.5,"unit":"Tbsps","original":"1 1/2 tablespoons milk"},{"name":"powdered sugar","amount":2,"unit":"cups","original":"2 cups powdered sugar"},{"name":"salt","amount":0.75,"unit":"tsps","original":"3/4 teaspoon salt"},{"name":"sugar","amount":0.25,"unit":"cups","original":"1/4 cup sugar"}]'::jsonb, '["Combine flour, sugar, salt, baking powder, cinnamon. Stir in milk and egg until just combined. Fold in apple.","Pour oil into skillet so that it is approximately 1 1/2 deep.","Heat oil on high. Oil is ready when a little dough thrown in floats to top. Carefully add dough to oil in heaping teaspoons. Cook until brown, about 2 minutes, then flip. Cook another 1-2 minutes, until both sides are browned.","Transfer briefly to paper towels to absorb excess oil, then transfer to cooling rack. Make glaze by stirring milk and powdered sugar together in a small bowl.","Drizzle over apple fritters. Wait approximately 3 minutes for glaze to harden, then flip fritters and drizzle glaze over the other side. Best served warm."]'::jsonb),
  (715523, 'Chorizo and Beef Quinoa Stuffed Pepper', 'Chorizo and Beef Quinoa Stuffed Pepper is a gluten free main course.  One portion of this dish contains approximately 51g of protein, 37g of fat, and a total of 685 calories.', 'https://img.spoonacular.com/recipes/715523-312x231.jpg', 'https://www.pinkwhen.com/chorizo-and-beef-quinoa-stuffed-pepper-recipe/', 30, 4, '[{"name":"bell peppers","amount":4,"unit":"servings","original":"bell peppers"},{"name":"cayenne","amount":0.5,"unit":"tsps","original":"½ tsp cayenne"},{"name":"chili powder","amount":0.25,"unit":"tsps","original":"¼ tsp chili powder"},{"name":"chorizo","amount":1,"unit":"lb","original":"1 pound chorizo"},{"name":"cumin","amount":0.25,"unit":"tsps","original":"¼ tsp cumin"},{"name":"green onion tops","amount":4,"unit":"servings","original":"green onion tops"},{"name":"monterrey jack and cheddar cheese","amount":0.25,"unit":"cups","original":"¼ cup mixed monterrey jack and cheddar cheese"},{"name":"ground beef","amount":1,"unit":"lb","original":"1 pound lean ground beef"},{"name":"quinoa","amount":1,"unit":"cup","original":"1 cup quinoa"}]'::jsonb, '["The first thing you will want to do is heat the oven to 350, boil the water for the quinoa, and in a separate skillet brown the beef and chorizo together.","Drain the meat mixture well, and then place into a medium mixing bowl.Once your quinoa is fully cooked, add it to the mixing bowl.","Add the green onion tops, cumin, cayenne, chili powder, and monterrey jack and cheddar cheese.","Mix well.","Cut the tops from your bell peppers and scoop out any remaining seeds.Then take your meat mixture and start stuffing the bell peppers until they are full.","Sprinkle with a little cheese and then bake in the oven for about 10 minutes until the bell pepper has softened.","Serve immediately."]'::jsonb),
  (715515, 'Southern Style Green Bean', 'The recipe Southern Style Green Bean can be made in about 40 minutes.  Watching your figure?', 'https://img.spoonacular.com/recipes/715515-312x231.jpg', 'https://www.pinkwhen.com/southern-style-green-bean-recipe/', 40, 2, '[{"name":"bacon","amount":3,"unit":"slice","original":"3 bacon slices, cut into one inch slices"},{"name":"butter","amount":0.5,"unit":"stick","original":"½ stick of butter"},{"name":"green beans","amount":2,"unit":"servings","original":"fresh green beans"},{"name":"new potatoes","amount":5,"unit":"","original":"5 new potatoes (quartered)"},{"name":"parsley","amount":2,"unit":"tsps","original":"2 tsp parsley"},{"name":"salt","amount":0.5,"unit":"tsps","original":"½ tsp salt"},{"name":"thyme","amount":1,"unit":"tsp","original":"1 tsp thyme"},{"name":"onion","amount":1,"unit":"medium","original":"medium white onion, finely chopped"}]'::jsonb, '["In a medium pot on medium heat, melt butter and then place the bacon pieces into the pot. Allow to cook for a couple of minutes and then add in the onion, thyme, and parsley. Allow to cook for 10 minutes, stirring frequently.","Add in the green beans and the quartered new potatoes and then cover with water and turn the heat up until they come to a boil. Once they start a small boil, turn the heat down to a simmer and cover. Cook for 20 minutes covered, stirring occasionally."]'::jsonb)
